var token = env.get('CLOUD_DEVICE_TOKEN') || '';
if (!token) {
    node.status({fill:'red', shape:'ring', text:'CLOUD_DEVICE_TOKEN fehlt'});
    node.error('CLOUD_DEVICE_TOKEN fehlt. In Pi-Hub /integrations anzeigen und in Node-RED Tab-Env eintragen.', msg);
    return null;
}
var payload = msg.payload || {};
if (!payload.component) payload.component = 'node_red';
if (!payload.status) payload.status = 'info';
if (!payload.ts) payload.ts = new Date().toISOString();
if (!payload.device) payload.device = env.get('DEFAULT_DEVICE_LABEL') || 'drainpress';
msg.payload = payload;
msg._pihubOriginalPayload = JSON.parse(JSON.stringify(payload));
msg.method = 'POST';
msg.url = env.get('CLOUD_BRIDGE_URL');
msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
};
node.status({fill:'blue', shape:'dot', text:'send cloud'});
return msg;

var original = msg._pihubOriginalPayload || msg.payload || {};
msg.payload = original;
if (!msg.payload.component) msg.payload.component = 'node_red_fallback';
if (!msg.payload.status) msg.payload.status = 'warning';
if (!msg.payload.ts) msg.payload.ts = new Date().toISOString();
msg.method = 'POST';
msg.url = env.get('LOCAL_API_URL') || 'http://127.0.0.1:3000/api/public/ingest/event';
msg.headers = { 'Content-Type': 'application/json' };
var localToken = env.get('PI_INGEST_TOKEN') || '';
if (localToken) msg.headers.Authorization = 'Bearer ' + localToken;
node.status({fill:'yellow', shape:'ring', text:'cloud failed -> local RAM fallback'});
node.warn('Cloud-Bridge nicht erreichbar oder 401. Sende lokal als RAM-Fallback. Prüfe CLOUD_DEVICE_TOKEN, nicht Revocation/Factory Token.');
return msg;

global.set('zisterne_strategy', {
    pv_min_w: 300, tibber_max_ct: 30, heat_start_hour: 11, heat_end_hour: 16,
    run_minutes: 10, max_minutes_per_day: 30, rain_veto_mm: 0.1
});
global.set('zisterne_eco_paused', false);
return null;

var token = env.get('CLOUD_DEVICE_TOKEN') || '';
if (!token) {
    node.status({fill:'red', shape:'ring', text:'CLOUD_DEVICE_TOKEN fehlt'});
    return null;
}
msg.method = 'GET';
msg.url = env.get('CLOUD_STRATEGY_URL');
msg.headers = { 'Authorization': 'Bearer ' + token };
return msg;

if (msg.statusCode >= 200 && msg.statusCode < 300 && msg.payload && msg.payload.params) {
    global.set('zisterne_strategy', msg.payload.params);
    global.set('zisterne_eco_paused', msg.payload.eco_paused === true);
    node.status({fill:'green', shape:'dot', text:'strategy updated'});
} else {
    node.status({fill:'yellow', shape:'ring', text:'strategy failed ' + msg.statusCode});
    node.warn(msg.payload || msg.error || 'Strategy poll failed');
}
return null;

var token = env.get('CLOUD_DEVICE_TOKEN') || '';
if (!token) { node.status({fill:'red', shape:'ring', text:'CLOUD_DEVICE_TOKEN fehlt'}); return null; }
msg.method = 'GET';
msg.url = env.get('CLOUD_COMMAND_POLL_URL');
msg.headers = { 'Authorization': 'Bearer ' + token };
return msg;

var cmd = msg.payload && msg.payload.command;
if (!cmd || !cmd.id) return null;
var kind = cmd.kind;
var p = cmd.payload || {};
var result = { id: cmd.id, ok: true, result: { handled_by: 'nodered', kind: kind } };

if (kind === 'plugin_manual') {
    var action = (p.action === 'off') ? 'OFF' : 'ON';
    var minutes = Math.max(1, Math.min(120, Number(p.minutes || 10)));
    var topic = env.get('MQTT_COMMAND_TOPIC') || 'cmnd/zisterne/POWER';
    var mqtt = {
        topic: topic,
        payload: action,
        _pihubCommandId: cmd.id
    };
    if (action === 'ON') {
        // Trigger node reads msg.delay (ms) for auto-OFF
        mqtt.delay = minutes * 60 * 1000;
    } else {
        // Cancels any pending auto-OFF in the trigger node
        mqtt.reset = true;
    }
    result.result.action = action;
    result.result.minutes = minutes;
    result.result.topic = topic;
    result.result.auto_off_in_ms = (action === 'ON') ? mqtt.delay : 0;
    node.status({ fill: action === 'ON' ? 'green' : 'grey', shape: 'dot', text: action + (action === 'ON' ? (' ' + minutes + 'm') : '') });
    return [mqtt, { payload: result }];
}

if (kind === 'mqtt_publish') {
    var t = String(p.topic || '');
    if (!t) return [null, { payload: { id: cmd.id, ok: false, result: { error: 'missing topic' } } }];
    var mqtt2 = { topic: t, payload: String(p.payload || ''), _pihubCommandId: cmd.id };
    result.result.topic = t;
    return [mqtt2, { payload: result }];
}

if (kind === 'status') {
    // Cloud/Alexa 'test node-red' ping. Just ack.
    result.result.pong = new Date().toISOString();
    return [null, { payload: result }];
}

return [null, { payload: { id: cmd.id, ok: false, result: { error: 'unsupported command for Node-RED runner: ' + kind } } }];

var token = env.get('CLOUD_DEVICE_TOKEN') || '';
if (!token) { node.error('CLOUD_DEVICE_TOKEN fehlt; kann Command Result nicht senden.', msg); return null; }
msg.method = 'POST';
msg.url = env.get('CLOUD_COMMAND_RESULT_URL');
msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
};
return msg;
